import React, { useState, useEffect } from 'react';

function App() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [cart, setCart] = useState([]);

  useEffect(() => {
    fetch('http://localhost:5000/api/products')
      .then(res => {
        if (!res.ok) {
          throw new Error('Server returned status: ' + res.status);
        }
        return res.json();
      })
      .then(data => setBooks(data))
      .catch(err => {
        console.error(err);
        setError('Failed to load books: ' + err.message);
      });
  }, []);

  const addToCart = (book) => {
    setCart([...cart, book]);
  };

  const removeFromCart = (indexToRemove) => {
    setCart(cart.filter((_, index) => index !== indexToRemove));
  };

  const cartTotal = cart.reduce((total, book) => total + book.price, 0);

  const filteredBooks = books.filter(book => {
    const matchesSearch = book.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          book.author.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || book.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial, sans-serif', backgroundColor: '#f4f7f6', minHeight: '100vh', display: 'flex', gap: '20px' }}>
      
      <div style={{ flex: 3 }}>
        <h1 style={{ textAlign: 'center', color: '#333', marginBottom: '20px', fontWeight: 'bold' }}>Bookstore Platform</h1>
        
        {error && (
          <div style={{ color: 'red', textAlign: 'center', marginBottom: '20px', fontWeight: 'bold' }}>
            {error}
          </div>
        )}

        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '15px', marginBottom: '40px' }}>
          <input 
            type="text" 
            placeholder="Search by title or author..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            style={{ 
              padding: '12px 20px', 
              width: '100%', 
              maxWidth: '500px', 
              borderRadius: '25px', 
              border: '1px solid #ccc', 
              fontSize: '16px',
              outline: 'none',
              boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
            }}
          />

          <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', justifyContent: 'center' }}>
            {['All', 'Stories', 'Science', 'History', 'Tech'].map(category => (
              <button 
                key={category}
                onClick={() => setSelectedCategory(category)}
                style={{
                  padding: '8px 24px',
                  borderRadius: '20px',
                  border: 'none',
                  cursor: 'pointer',
                  fontWeight: 'bold',
                  backgroundColor: selectedCategory === category ? '#007bff' : '#fff',
                  color: selectedCategory === category ? '#fff' : '#555',
                  boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
                }}
              >
                {category}
              </button>
            ))}
          </div>
        </div>
        
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(3, 1fr)', 
          gap: '30px', 
          maxWidth: '1000px', 
          margin: '0 auto' 
        }}>
          {filteredBooks.map(book => (
            <div key={book.id} style={{ 
              backgroundColor: '#fff', 
              padding: '20px', 
              borderRadius: '12px', 
              boxShadow: '0 4px 12px rgba(0,0,0,0.08)', 
              display: 'flex', 
              flexDirection: 'column', 
              alignItems: 'center',
              textAlign: 'center'
            }}>
              <img 
                src="https://images.unsplash.com/photo-1543002588-bfa74002ed7e?w=500&auto=format&fit=crop&q=60" 
                alt="Book Cover" 
                style={{ width: '140px', height: '200px', objectFit: 'cover', borderRadius: '6px', marginBottom: '15px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}
              />
              <h3 style={{ margin: '10px 0 5px 0', color: '#2c3e50', fontSize: '18px', height: '44px', overflow: 'hidden' }}>{book.title}</h3>
              <p style={{ margin: '5px 0', color: '#7f8c8d', fontSize: '14px' }}><strong>Author:</strong> {book.author}</p>
              <p style={{ margin: '5px 0', color: '#007bff', fontSize: '12px', fontWeight: 'bold' }}>{book.category}</p>
              <p style={{ margin: '15px 0', fontWeight: 'bold', color: '#27ae60', fontSize: '20px' }}>${book.price}</p>
              <button 
                onClick={() => addToCart(book)}
                style={{ 
                  backgroundColor: '#007bff', 
                  color: '#fff', 
                  border: 'none', 
                  padding: '10px 20px', 
                  borderRadius: '6px', 
                  cursor: 'pointer', 
                  fontWeight: 'bold',
                  width: '100%',
                  marginTop: 'auto'
                }}
              >
                Add to Cart
              </button>
            </div>
          ))}
        </div>

        {filteredBooks.length === 0 && (
          <p style={{ textAlign: 'center', color: '#999', fontSize: '18px', marginTop: '40px' }}>No books found.</p>
        )}
      </div>

      <div style={{ flex: 1, backgroundColor: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)', height: 'fit-content', minWidth: '250px' }}>
        <h2 style={{ color: '#333', borderBottom: '2px solid #f4f7f6', paddingBottom: '10px' }}>Shopping Cart ({cart.length})</h2>
        {cart.length === 0 ? (
          <p style={{ color: '#999' }}>Your cart is empty.</p>
        ) : (
          <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
            {cart.map((item, index) => (
              <li key={index} style={{ display: 'flex', justifyContent: 'between', alignItems: 'center', marginBottom: '10px', backgroundColor: '#fafafa', padding: '10px', borderRadius: '6px' }}>
                <div style={{ flex: 1 }}>
                  <span style={{ fontWeight: 'bold', fontSize: '14px', display: 'block' }}>{item.title}</span>
                  <span style={{ color: '#27ae60', fontSize: '14px' }}>${item.price}</span>
                </div>
                <button 
                  onClick={() => removeFromCart(index)}
                  style={{ backgroundColor: '#ff4d4d', color: '#fff', border: 'none', borderRadius: '4px', padding: '5px 10px', cursor: 'pointer', fontSize: '12px' }}
                >
                  Remove
                </button>
              </li>
            ))}
          </ul>
        )}
        <div style={{ marginTop: '20px', borderTop: '2px solid #f4f7f6', paddingTop: '15px', display: 'flex', justifyContent: 'space-between', fontWeight: 'bold', fontSize: '18px' }}>
          <span>Total:</span>
          <span style={{ color: '#27ae60' }}>${cartTotal}</span>
        </div>
      </div>

    </div>
  );
}

export default App;
